import sys

class Solution:
    def minWindow(self, S: str, T: str) -> str:
        if not T or not S:
            return "-1"

        need = {}
        for char in T:
            need[char] = need.get(char, 0) + 1

        required = len(need)
        left = 0
        right = 0
        formed = 0
        window = {}
        min_len = float('inf')
        min_window = None

        while right < len(S):
            character = S[right]
            window[character] = window.get(character, 0) + 1
            if character in need and window[character] == need[character]:
                formed += 1

            while left <= right and formed == required:
                character = S[left]
                if right - left + 1 < min_len:
                    min_len = right - left + 1
                    min_window = S[left:right + 1]

                window[character] -= 1
                if character in need and window[character] < need[character]:
                    formed -= 1
                left += 1
            right += 1
        return min_window if min_window else "-1"

