#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    string minWindow(string S, string T) {
        if (T.empty() || S.empty()) {
            return "-1";
        }

        unordered_map<char, int> need;
        for (char c : T) {
            need[c]++;
        }

        int required = need.size();
        int left = 0;
        int right = 0;
        int formed = 0;
        unordered_map<char, int> window;
        int min_len = INT_MAX;
        string min_window;

        while (right < S.size()) {
            char character = S[right];
            window[character]++;
            if (need.find(character) != need.end() && window[character] == need[character]) {
                formed++;
            }

            while (left <= right && formed == required) {
                character = S[left];
                if (right - left + 1 < min_len) {
                    min_len = right - left + 1;
                    min_window = S.substr(left, right - left + 1);
                }

                window[character]--;
                if (need.find(character) != need.end() && window[character] < need[character]) {
                    formed--;
                }
                left++;
            }
            right++;
        }
        return min_window.empty() ? "-1" : min_window;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    string S;
    cin >> S;
    int m;
    if (!(cin >> m)) return 0;
    string T;
    cin >> T;
    Solution sol;
    string ans = sol.minWindow(S, T);
    cout << ans << "\n";
    return 0;
}
